const obj = $input.first().json.data.object;
const subId = obj.subscription || '';
const email = obj.customer_email || (obj.customer_details && obj.customer_details.email) || '';

const salt = 'sinapseia2024';
let h1 = 5381, h2 = 2166136261;
const str = subId + salt;
for (let i = 0; i < str.length; i++) {
  const c = str.charCodeAt(i);
  h1 = ((h1 * 33) ^ c) >>> 0;
  h2 = (Math.imul(h2 ^ c, 16777619)) >>> 0;
}
const toHex = n => {
  const s = (n & 0xFFFF).toString(16).toUpperCase();
  return '0000'.slice(s.length) + s;
};
const chave = 'SINAPSE-' + toHex(h1) + '-' + toHex(h2) + '-' + toHex(h1 ^ h2);

return [{ json: { chave, email, subscription_id: subId } }];
